            if(isChrome69) {
                setTimeout(function(){
                    page_params.chrome_69_bandaid = {
                        iframes: []
                    };
                    document.querySelectorAll('iframe').forEach( function(item){
                        page_params.chrome_69_bandaid.iframes.push({
